14	 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
15	 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
16	 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
17	 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
18	 *
19	 */
20	
21	#ifndef FUNCTIONAL_H
22	#define FUNCTIONAL_H
23	
24	#include "kernel/yosys.h"
25	#include "kernel/compute_graph.h"
26	#include "kernel/drivertools.h"
27	#include "kernel/mem.h"
28	#include "kernel/utils.h"
29	
30	USING_YOSYS_NAMESPACE
31	YOSYS_NAMESPACE_BEGIN
32	
33	namespace Functional {
34		// each function is documented with a short pseudocode declaration or definition
35		// standard C/Verilog operators are used to describe the result
36		//
37		// the sorts used in this are:
38		// - bit[N]: a bitvector of N bits
39		//   bit[N] can be indicated as signed or unsigned. this is not tracked by the functional backend
40		//   but is meant to indicate how the value is interpreted
41		//   if a bit[N] is marked as neither signed nor unsigned, this means the result should be valid with *either* interpretation
42		// - memory[N, M]: a memory with N address and M data bits
43		// - int: C++ int
44		// - Const[N]: yosys RTLIL::Const (with size() == N)
45		// - IdString: yosys IdString
46		// - any: used in documentation to indicate that the sort is unconstrained
47		//
48		// nodes in the functional backend are either of sort bit[N] or memory[N,M] (for some N, M: int)
49		// additionally, they can carry a constant of sort int, Const[N] or IdString
50		// each node has a 'sort' field that stores the sort of the node
51		// slice, zero_extend, sign_extend use the sort field to store out_width
52		enum class Fn {
53			// invalid() = known-invalid/shouldn't happen value
54			// TODO: maybe remove this and use e.g. std::optional instead?
55			invalid,
56			// buf(a: any): any = a
57			// no-op operation
58			// when constructing the compute graph we generate invalid buf() nodes as a placeholder
59			// and later insert the argument
60			buf,
61			// slice(a: bit[in_width], offset: int, out_width: int): bit[out_width] = a[offset +: out_width]
62			// required: offset + out_width <= in_width
63			slice,
64			// zero_extend(a: unsigned bit[in_width], out_width: int): unsigned bit[out_width] = a (zero extended)
65			// required: out_width > in_width
66			zero_extend,
67			// sign_extend(a: signed bit[in_width], out_width: int): signed bit[out_width] = a (sign extended)
68			// required: out_width > in_width
69			sign_extend,
70			// concat(a: bit[N], b: bit[M]): bit[N+M] = {b, a} (verilog syntax)
71			// concatenates two bitvectors, with a in the least significant position and b in the more significant position
72			concat,
73			// add(a: bit[N], b: bit[N]): bit[N] = a + b
74			add,
75			// sub(a: bit[N], b: bit[N]): bit[N] = a - b
76			sub,
77			// mul(a: bit[N], b: bit[N]): bit[N] = a * b
78			mul,
79			// unsigned_div(a: unsigned bit[N], b: unsigned bit[N]): bit[N] = a / b
80			unsigned_div,
81			// unsigned_mod(a: signed bit[N], b: signed bit[N]): bit[N] = a % b
82			unsigned_mod,
83			// bitwise_and(a: bit[N], b: bit[N]): bit[N] = a & b
84			bitwise_and,
85			// bitwise_or(a: bit[N], b: bit[N]): bit[N] = a | b
86			bitwise_or,
87			// bitwise_xor(a: bit[N], b: bit[N]): bit[N] = a ^ b
88			bitwise_xor,
89			// bitwise_not(a: bit[N]): bit[N] = ~a
90			bitwise_not,
91			// reduce_and(a: bit[N]): bit[1] = &a
92			reduce_and,
93			// reduce_or(a: bit[N]): bit[1] = |a
94			reduce_or,
95			// reduce_xor(a: bit[N]): bit[1] = ^a
96			reduce_xor,
97			// unary_minus(a: bit[N]): bit[N] = -a
98			unary_minus,
99			// equal(a: bit[N], b: bit[N]): bit[1] = (a == b)
100			equal,
101			// not_equal(a: bit[N], b: bit[N]): bit[1] = (a != b)
102			not_equal,
103			// signed_greater_than(a: signed bit[N], b: signed bit[N]): bit[1] = (a > b)
104			signed_greater_than,
105			// signed_greater_equal(a: signed bit[N], b: signed bit[N]): bit[1] = (a >= b)
106			signed_greater_equal,
107			// unsigned_greater_than(a: unsigned bit[N], b: unsigned bit[N]): bit[1] = (a > b)
108			unsigned_greater_than,
109			// unsigned_greater_equal(a: unsigned bit[N], b: unsigned bit[N]): bit[1] = (a >= b)
110			unsigned_greater_equal,
111			// logical_shift_left(a: bit[N], b: unsigned bit[M]): bit[N] = a << b
112			// required: M == clog2(N)
113			logical_shift_left,
114			// logical_shift_right(a: unsigned bit[N], b: unsigned bit[M]): unsigned bit[N] = a >> b
115			// required: M == clog2(N)
116			logical_shift_right,
117			// arithmetic_shift_right(a: signed bit[N], b: unsigned bit[M]): signed bit[N] = a >> b
118			// required: M == clog2(N)
119			arithmetic_shift_right,
120			// mux(a: bit[N], b: bit[N], s: bit[1]): bit[N] = s ? b : a
121			mux,
122			// constant(a: Const[N]): bit[N] = a
123			constant,
124			// input(a: IdString): any
125			// returns the current value of the input with the specified name
126			input,
127			// state(a: IdString): any
128			// returns the current value of the state variable with the specified name
129			state,
130			// memory_read(memory: memory[addr_width, data_width], addr: bit[addr_width]): bit[data_width] = memory[addr]
131			memory_read,
132			// memory_write(memory: memory[addr_width, data_width], addr: bit[addr_width], data: bit[data_width]): memory[addr_width, data_width]
133			// returns a copy of `memory` but with the value at `addr` changed to `data`
134			memory_write
135		};
136		// returns the name of a Fn value, as a string literal
137		const char *fn_to_string(Fn);
138		// Sort represents the sort or type of a node
139		// currently the only two sorts are signal/bit and memory
140		class Sort {
141			std::variant<int, std::pair<int, int>> _v;
142		public:
143			explicit Sort(int width) : _v(width) { }
144			Sort(int addr_width, int data_width) : _v(std::make_pair(addr_width, data_width)) { }
145			bool is_signal() const { return _v.index() == 0; }
146			bool is_memory() const { return _v.index() == 1; }
147			// returns the width of a bitvector sort, errors out for other sorts
148			int width() const { return std::get<0>(_v); }
149			// returns the address width of a bitvector sort, errors out for other sorts
150			int addr_width() const { return std::get<1>(_v).first; }
151			// returns the data width of a bitvector sort, errors out for other sorts
152			int data_width() const { return std::get<1>(_v).second; }
153			bool operator==(Sort const& other) const { return _v == other._v; }
154			[[nodiscard]] Hasher hash_into(Hasher h) const { h.eat(_v); return h; }
155		};
156		class IR;
157		class Factory;
158		class Node;
159		class IRInput {
160			friend class Factory;
161		public:
162			IdString name;
163			IdString kind;
164			Sort sort;
165		private:
166			IRInput(IR &, IdString name, IdString kind, Sort sort)
167			: name(name), kind(kind), sort(std::move(sort)) {}
168		};
169		class IROutput {
170			friend class Factory;
171			IR &_ir;
172		public:
173			IdString name;
174			IdString kind;
175			Sort sort;
176		private:
177			IROutput(IR &ir, IdString name, IdString kind, Sort sort)
178			: _ir(ir), name(name), kind(kind), sort(std::move(sort)) {}
179		public:
180			Node value() const;
181			bool has_value() const;
182			void set_value(Node value);
183		};
184		class IRState {
185			friend class Factory;
186			IR &_ir;
187		public:
188			IdString name;
189			IdString kind;
190			Sort sort;
191		private:
192			std::variant<RTLIL::Const, MemContents> _initial;
193			IRState(IR &ir, IdString name, IdString kind, Sort sort)
194			: _ir(ir), name(name), kind(kind), sort(std::move(sort)) {}
195		public:
196			Node next_value() const;
197			bool has_next_value() const;
198			RTLIL::Const const& initial_value_signal() const { return std::get<RTLIL::Const>(_initial); }
199			MemContents const& initial_value_memory() const { return std::get<MemContents>(_initial); }
200			void set_next_value(Node value);
201			void set_initial_value(RTLIL::Const value) { value.extu(sort.width()); _initial = std::move(value); }
202			void set_initial_value(MemContents value) { log_assert(Sort(value.addr_width(), value.data_width()) == sort); _initial = std::move(value); }
203		};
204		class IR {
205			friend class Factory;
206			friend class Node;
207			friend class IRInput;
208			friend class IROutput;
209			friend class IRState;
210			// one NodeData is stored per Node, containing the function and non-node arguments
211			// note that NodeData is deduplicated by ComputeGraph
212			class NodeData {
213				Fn _fn;
214				std::variant<
215					std::monostate,
216					RTLIL::Const,
217					std::pair<IdString, IdString>,
218					int
219				> _extra;
220			public:
221				NodeData() : _fn(Fn::invalid) {}
222				NodeData(Fn fn) : _fn(fn) {}
223				template<class T> NodeData(Fn fn, T &&extra) : _fn(fn), _extra(std::forward<T>(extra)) {}
224				Fn fn() const { return _fn; }
225				const RTLIL::Const &as_const() const { return std::get<RTLIL::Const>(_extra); }
226				std::pair<IdString, IdString> as_idstring_pair() const { return std::get<std::pair<IdString, IdString>>(_extra); }
227				int as_int() const { return std::get<int>(_extra); }
228				[[nodiscard]] Hasher hash_into(Hasher h) const {
229					h.eat((unsigned int) _fn);
230					h.eat(_extra);
231					return h;
232				}
233				bool operator==(NodeData const &other) const {
234					return _fn == other._fn && _extra == other._extra;
235				}
236			};
237			// Attr contains all the information about a note that should not be deduplicated
238			struct Attr {
239				Sort sort;
240			};
241			// our specialised version of ComputeGraph
242			// the sparse_attr IdString stores a naming suggestion, retrieved with name()
243			// the key is currently used to identify the nodes that represent output and next state values
244			// the bool is true for next state values
245			using Graph = ComputeGraph<NodeData, Attr, IdString, std::tuple<IdString, IdString, bool>>;
246			Graph _graph;
247			dict<std::pair<IdString, IdString>, IRInput> _inputs;
248			dict<std::pair<IdString, IdString>, IROutput> _outputs;
249			dict<std::pair<IdString, IdString>, IRState> _states;
250			IR::Graph::Ref mutate(Node n);
251		public:
252			static IR from_module(Module *module);
253			Factory factory();
254			int size() const { return _graph.size(); }
255			Node operator[](int i);
256			void topological_sort();
257			void forward_buf();
258			IRInput const& input(IdString name, IdString kind) const { return _inputs.at({name, kind}); }
259			IRInput const& input(IdString name) const { return input(name, ID($input)); }
260			IROutput const& output(IdString name, IdString kind) const { return _outputs.at({name, kind}); }
261			IROutput const& output(IdString name) const { return output(name, ID($output)); }
262			IRState const& state(IdString name, IdString kind) const { return _states.at({name, kind}); }
263			IRState const& state(IdString name) const { return state(name, ID($state)); }
264			bool has_input(IdString name, IdString kind) const { return _inputs.count({name, kind}); }
265			bool has_output(IdString name, IdString kind) const { return _outputs.count({name, kind}); }
266			bool has_state(IdString name, IdString kind) const { return _states.count({name, kind}); }
267			vector<IRInput const*> inputs(IdString kind) const;
268			vector<IRInput const*> inputs() const { return inputs(ID($input)); }
269			vector<IROutput const*> outputs(IdString kind) const;
270			vector<IROutput const*> outputs() const { return outputs(ID($output)); }
271			vector<IRState const*> states(IdString kind) const;
272			vector<IRState const*> states() const { return states(ID($state)); }
273			vector<IRInput const*> all_inputs() const;
274			vector<IROutput const*> all_outputs() const;
275			vector<IRState const*> all_states() const;
276			class iterator {
277				friend class IR;
278				IR *_ir;
279				int _index;
280				iterator(IR *ir, int index) : _ir(ir), _index(index) {}
281			public:
282				using iterator_category = std::input_iterator_tag;
283				using value_type = Node;
284				using pointer = arrow_proxy<Node>;
285				using reference = Node;
286				using difference_type = ptrdiff_t;
287				Node operator*();
288				iterator &operator++() { _index++; return *this; }
289				bool operator!=(iterator const &other) const { return _ir != other._ir || _index != other._index; }
290				bool operator==(iterator const &other) const { return !(*this != other); }
291				pointer operator->();
292			};
293			iterator begin() { return iterator(this, 0); }
294			iterator end() { return iterator(this, _graph.size()); }
295		};
296		// Node is an immutable reference to a FunctionalIR node
297		class Node {
298			friend class Factory;
299			friend class IR;
300			friend class IRInput;
301			friend class IROutput;
302			friend class IRState;
303			IR::Graph::ConstRef _ref;
304			explicit Node(IR::Graph::ConstRef ref) : _ref(ref) { }
305			explicit operator IR::Graph::ConstRef() { return _ref; }
306		public:
307			// the node's index. may change if nodes are added or removed
308			int id() const { return _ref.index(); }
309			// a name suggestion for the node, which need not be unique
310			IdString name() const {
311				if(_ref.has_sparse_attr())
312					return _ref.sparse_attr();
313				else
314					return std::string("\\n") + std::to_string(id());
315			}
316			Fn fn() const { return _ref.function().fn(); }
317			Sort sort() const { return _ref.attr().sort; }
318			// returns the width of a bitvector node, errors out for other nodes
319			int width() const { return sort().width(); }
320			size_t arg_count() const { return _ref.size(); }
321			Node arg(int n) const { return Node(_ref.arg(n)); }
322			// visit calls the appropriate visitor method depending on the type of the node
323			template<class Visitor> auto visit(Visitor v) const
324			{
325				// currently templated but could be switched to AbstractVisitor &
326				switch(_ref.function().fn()) {
327				case Fn::invalid: log_error("invalid node in visit"); break;
328				case Fn::buf: return v.buf(*this, arg(0)); break;
329				case Fn::slice: return v.slice(*this, arg(0), _ref.function().as_int(), sort().width()); break;
330				case Fn::zero_extend: return v.zero_extend(*this, arg(0), width()); break;
331				case Fn::sign_extend: return v.sign_extend(*this, arg(0), width()); break;
332				case Fn::concat: return v.concat(*this, arg(0), arg(1)); break;
333				case Fn::add: return v.add(*this, arg(0), arg(1)); break;
334				case Fn::sub: return v.sub(*this, arg(0), arg(1)); break;
335				case Fn::mul: return v.mul(*this, arg(0), arg(1)); break;
336				case Fn::unsigned_div: return v.unsigned_div(*this, arg(0), arg(1)); break;
337				case Fn::unsigned_mod: return v.unsigned_mod(*this, arg(0), arg(1)); break;
338				case Fn::bitwise_and: return v.bitwise_and(*this, arg(0), arg(1)); break;
339				case Fn::bitwise_or: return v.bitwise_or(*this, arg(0), arg(1)); break;
340				case Fn::bitwise_xor: return v.bitwise_xor(*this, arg(0), arg(1)); break;
341				case Fn::bitwise_not: return v.bitwise_not(*this, arg(0)); break;
342				case Fn::unary_minus: return v.unary_minus(*this, arg(0)); break;
343				case Fn::reduce_and: return v.reduce_and(*this, arg(0)); break;
344				case Fn::reduce_or: return v.reduce_or(*this, arg(0)); break;
345				case Fn::reduce_xor: return v.reduce_xor(*this, arg(0)); break;
346				case Fn::equal: return v.equal(*this, arg(0), arg(1)); break;
347				case Fn::not_equal: return v.not_equal(*this, arg(0), arg(1)); break;
348				case Fn::signed_greater_than: return v.signed_greater_than(*this, arg(0), arg(1)); break;
349				case Fn::signed_greater_equal: return v.signed_greater_equal(*this, arg(0), arg(1)); break;
350				case Fn::unsigned_greater_than: return v.unsigned_greater_than(*this, arg(0), arg(1)); break;
351				case Fn::unsigned_greater_equal: return v.unsigned_greater_equal(*this, arg(0), arg(1)); break;
352				case Fn::logical_shift_left: return v.logical_shift_left(*this, arg(0), arg(1)); break;
353				case Fn::logical_shift_right: return v.logical_shift_right(*this, arg(0), arg(1)); break;
354				case Fn::arithmetic_shift_right: return v.arithmetic_shift_right(*this, arg(0), arg(1)); break;
355				case Fn::mux: return v.mux(*this, arg(0), arg(1), arg(2)); break;
356				case Fn::constant: return v.constant(*this, _ref.function().as_const()); break;
357				case Fn::input: return v.input(*this, _ref.function().as_idstring_pair().first, _ref.function().as_idstring_pair().second); break;
358				case Fn::state: return v.state(*this, _ref.function().as_idstring_pair().first, _ref.function().as_idstring_pair().second); break;
359				case Fn::memory_read: return v.memory_read(*this, arg(0), arg(1)); break;
360				case Fn::memory_write: return v.memory_write(*this, arg(0), arg(1), arg(2)); break;
361				}
362				log_abort();
363			}
364			std::string to_string();
365			std::string to_string(std::function<std::string(Node)>);
366		};
367		inline IR::Graph::Ref IR::mutate(Node n) { return _graph[n._ref.index()]; }
368		inline Node IR::operator[](int i) { return Node(_graph[i]); }
369		inline Node IROutput::value() const { return Node(_ir._graph({name, kind, false})); }
370		inline bool IROutput::has_value() const { return _ir._graph.has_key({name, kind, false}); }
371		inline void IROutput::set_value(Node value) { log_assert(sort == value.sort()); _ir.mutate(value).assign_key({name, kind, false}); }
372		inline Node IRState::next_value() const { return Node(_ir._graph({name, kind, true})); }
373		inline bool IRState::has_next_value() const { return _ir._graph.has_key({name, kind, true}); }
374		inline void IRState::set_next_value(Node value) { log_assert(sort == value.sort()); _ir.mutate(value).assign_key({name, kind, true}); }
375		inline Node IR::iterator::operator*() { return Node(_ir->_graph[_index]); }
376		inline arrow_proxy<Node> IR::iterator::operator->() { return arrow_proxy<Node>(**this); }
377		// AbstractVisitor provides an abstract base class for visitors
378		template<class T> struct AbstractVisitor {
379			virtual T buf(Node self, Node n) = 0;
380			virtual T slice(Node self, Node a, int offset, int out_width) = 0;
381			virtual T zero_extend(Node self, Node a, int out_width) = 0;
382			virtual T sign_extend(Node self, Node a, int out_width) = 0;
383			virtual T concat(Node self, Node a, Node b) = 0;
384			virtual T add(Node self, Node a, Node b) = 0;
385			virtual T sub(Node self, Node a, Node b) = 0;
386			virtual T mul(Node self, Node a, Node b) = 0;
387			virtual T unsigned_div(Node self, Node a, Node b) = 0;
388			virtual T unsigned_mod(Node self, Node a, Node b) = 0;
389			virtual T bitwise_and(Node self, Node a, Node b) = 0;
390			virtual T bitwise_or(Node self, Node a, Node b) = 0;
391			virtual T bitwise_xor(Node self, Node a, Node b) = 0;
392			virtual T bitwise_not(Node self, Node a) = 0;
393			virtual T unary_minus(Node self, Node a) = 0;
394			virtual T reduce_and(Node self, Node a) = 0;
395			virtual T reduce_or(Node self, Node a) = 0;
396			virtual T reduce_xor(Node self, Node a) = 0;
397			virtual T equal(Node self, Node a, Node b) = 0;
398			virtual T not_equal(Node self, Node a, Node b) = 0;
399			virtual T signed_greater_than(Node self, Node a, Node b) = 0;
400			virtual T signed_greater_equal(Node self, Node a, Node b) = 0;
401			virtual T unsigned_greater_than(Node self, Node a, Node b) = 0;
402			virtual T unsigned_greater_equal(Node self, Node a, Node b) = 0;
403			virtual T logical_shift_left(Node self, Node a, Node b) = 0;
404			virtual T logical_shift_right(Node self, Node a, Node b) = 0;
405			virtual T arithmetic_shift_right(Node self, Node a, Node b) = 0;
406			virtual T mux(Node self, Node a, Node b, Node s) = 0;
407			virtual T constant(Node self, RTLIL::Const const & value) = 0;
408			virtual T input(Node self, IdString name, IdString kind) = 0;
409			virtual T state(Node self, IdString name, IdString kind) = 0;
410			virtual T memory_read(Node self, Node mem, Node addr) = 0;
411			virtual T memory_write(Node self, Node mem, Node addr, Node data) = 0;
412		};
413		// DefaultVisitor provides defaults for all visitor methods which just calls default_handler
414		template<class T> struct DefaultVisitor : public AbstractVisitor<T> {
415			virtual T default_handler(Node self) = 0;
416			T buf(Node self, Node) override { return default_handler(self); }
417			T slice(Node self, Node, int, int) override { return default_handler(self); }
418			T zero_extend(Node self, Node, int) override { return default_handler(self); }
419			T sign_extend(Node self, Node, int) override { return default_handler(self); }
420			T concat(Node self, Node, Node) override { return default_handler(self); }
421			T add(Node self, Node, Node) override { return default_handler(self); }
422			T sub(Node self, Node, Node) override { return default_handler(self); }
423			T mul(Node self, Node, Node) override { return default_handler(self); }
424			T unsigned_div(Node self, Node, Node) override { return default_handler(self); }
425			T unsigned_mod(Node self, Node, Node) override { return default_handler(self); }
426			T bitwise_and(Node self, Node, Node) override { return default_handler(self); }
427			T bitwise_or(Node self, Node, Node) override { return default_handler(self); }
428			T bitwise_xor(Node self, Node, Node) override { return default_handler(self); }
429			T bitwise_not(Node self, Node) override { return default_handler(self); }
430			T unary_minus(Node self, Node) override { return default_handler(self); }
431			T reduce_and(Node self, Node) override { return default_handler(self); }
432			T reduce_or(Node self, Node) override { return default_handler(self); }
433			T reduce_xor(Node self, Node) override { return default_handler(self); }
434			T equal(Node self, Node, Node) override { return default_handler(self); }
435			T not_equal(Node self, Node, Node) override { return default_handler(self); }
436			T signed_greater_than(Node self, Node, Node) override { return default_handler(self); }
437			T signed_greater_equal(Node self, Node, Node) override { return default_handler(self); }
438			T unsigned_greater_than(Node self, Node, Node) override { return default_handler(self); }
439			T unsigned_greater_equal(Node self, Node, Node) override { return default_handler(self); }
440			T logical_shift_left(Node self, Node, Node) override { return default_handler(self); }
441			T logical_shift_right(Node self, Node, Node) override { return default_handler(self); }
442			T arithmetic_shift_right(Node self, Node, Node) override { return default_handler(self); }
443			T mux(Node self, Node, Node, Node) override { return default_handler(self); }
444			T constant(Node self, RTLIL::Const const &) override { return default_handler(self); }
445			T input(Node self, IdString, IdString) override { return default_handler(self); }
446			T state(Node self, IdString, IdString) override { return default_handler(self); }
447			T memory_read(Node self, Node, Node) override { return default_handler(self); }
448			T memory_write(Node self, Node, Node, Node) override { return default_handler(self); }
449		};
450		// a factory is used to modify a FunctionalIR. it creates new nodes and allows for some modification of existing nodes.
451		class Factory {
452			friend class IR;
453			IR &_ir;
454			explicit Factory(IR &ir) : _ir(ir) {}
455			Node add(IR::NodeData &&fn, Sort const &sort, std::initializer_list<Node> args) {
456				log_assert(!sort.is_signal() || sort.width() > 0);
457				log_assert(!sort.is_memory() || (sort.addr_width() > 0 && sort.data_width() > 0));
458				IR::Graph::Ref ref = _ir._graph.add(std::move(fn), {std::move(sort)});
459				for (auto arg : args)
460					ref.append_arg(IR::Graph::ConstRef(arg));
461				return Node(ref);
462			}
463			void check_basic_binary(Node const &a, Node const &b) { log_assert(a.sort().is_signal() && a.sort() == b.sort()); }
464			void check_shift(Node const &a, Node const &b) { log_assert(a.sort().is_signal() && b.sort().is_signal() && b.width() == ceil_log2(a.width())); }
465			void check_unary(Node const &a) { log_assert(a.sort().is_signal()); }
466		public:
467			IR &ir() { return _ir; }
468			Node slice(Node a, int offset, int out_width) {
469				log_assert(a.sort().is_signal() && offset + out_width <= a.sort().width());
470				if(offset == 0 && out_width == a.width())
471					return a;
472				return add(IR::NodeData(Fn::slice, offset), Sort(out_width), {a});
473			}
474			// extend will either extend or truncate the provided value to reach the desired width
475			Node extend(Node a, int out_width, bool is_signed) {
476				int in_width = a.sort().width();
477				log_assert(a.sort().is_signal());
478				if(in_width == out_width)
479					return a;
480				if(in_width > out_width)
481					return slice(a, 0, out_width);
482				if(is_signed)
483					return add(Fn::sign_extend, Sort(out_width), {a});
484				else
485					return add(Fn::zero_extend, Sort(out_width), {a});
486			}
487			Node concat(Node a, Node b) {
488				log_assert(a.sort().is_signal() && b.sort().is_signal());
489				return add(Fn::concat, Sort(a.sort().width() + b.sort().width()), {a, b});
490			}
491			Node add(Node a, Node b) { check_basic_binary(a, b); return add(Fn::add, a.sort(), {a, b}); }
492			Node sub(Node a, Node b) { check_basic_binary(a, b); return add(Fn::sub, a.sort(), {a, b}); }
493			Node mul(Node a, Node b) { check_basic_binary(a, b); return add(Fn::mul, a.sort(), {a, b}); }
494			Node unsigned_div(Node a, Node b) { check_basic_binary(a, b); return add(Fn::unsigned_div, a.sort(), {a, b}); }
495			Node unsigned_mod(Node a, Node b) { check_basic_binary(a, b); return add(Fn::unsigned_mod, a.sort(), {a, b}); }
496			Node bitwise_and(Node a, Node b) { check_basic_binary(a, b); return add(Fn::bitwise_and, a.sort(), {a, b}); }
497			Node bitwise_or(Node a, Node b) { check_basic_binary(a, b); return add(Fn::bitwise_or, a.sort(), {a, b}); }
498			Node bitwise_xor(Node a, Node b) { check_basic_binary(a, b); return add(Fn::bitwise_xor, a.sort(), {a, b}); }
499			Node bitwise_not(Node a) { check_unary(a); return add(Fn::bitwise_not, a.sort(), {a}); }
500			Node unary_minus(Node a) { check_unary(a); return add(Fn::unary_minus, a.sort(), {a}); }
501			Node reduce_and(Node a) {
502				check_unary(a);
503				if(a.width() == 1)
504					return a;
505				return add(Fn::reduce_and, Sort(1), {a});
506			}
507			Node reduce_or(Node a) {
508				check_unary(a);
509				if(a.width() == 1)
510					return a;
511				return add(Fn::reduce_or, Sort(1), {a});
512			}
513			Node reduce_xor(Node a) {
514				check_unary(a);
515				if(a.width() == 1)
516					return a;
517				return add(Fn::reduce_xor, Sort(1), {a});
518			}
519			Node equal(Node a, Node b) { check_basic_binary(a, b); return add(Fn::equal, Sort(1), {a, b}); }
520			Node not_equal(Node a, Node b) { check_basic_binary(a, b); return add(Fn::not_equal, Sort(1), {a, b}); }
521			Node signed_greater_than(Node a, Node b) { check_basic_binary(a, b); return add(Fn::signed_greater_than, Sort(1), {a, b}); }
522			Node signed_greater_equal(Node a, Node b) { check_basic_binary(a, b); return add(Fn::signed_greater_equal, Sort(1), {a, b}); }
523			Node unsigned_greater_than(Node a, Node b) { check_basic_binary(a, b); return add(Fn::unsigned_greater_than, Sort(1), {a, b}); }
524			Node unsigned_greater_equal(Node a, Node b) { check_basic_binary(a, b); return add(Fn::unsigned_greater_equal, Sort(1), {a, b}); }
525			Node logical_shift_left(Node a, Node b) { check_shift(a, b); return add(Fn::logical_shift_left, a.sort(), {a, b}); }
526			Node logical_shift_right(Node a, Node b) { check_shift(a, b); return add(Fn::logical_shift_right, a.sort(), {a, b}); }
527			Node arithmetic_shift_right(Node a, Node b) { check_shift(a, b); return add(Fn::arithmetic_shift_right, a.sort(), {a, b}); }
528			Node mux(Node a, Node b, Node s) {
529				log_assert(a.sort().is_signal() && a.sort() == b.sort() && s.sort() == Sort(1));
530				return add(Fn::mux, a.sort(), {a, b, s});
531			}
532			Node memory_read(Node mem, Node addr) {
533				log_assert(mem.sort().is_memory() && addr.sort().is_signal() && mem.sort().addr_width() == addr.sort().width());
534				return add(Fn::memory_read, Sort(mem.sort().data_width()), {mem, addr});
535			}
536			Node memory_write(Node mem, Node addr, Node data) {
537				log_assert(mem.sort().is_memory() && addr.sort().is_signal() && data.sort().is_signal() &&
538					mem.sort().addr_width() == addr.sort().width() && mem.sort().data_width() == data.sort().width());
539				return add(Fn::memory_write, mem.sort(), {mem, addr, data});
540			}
541			Node constant(RTLIL::Const value) {
542				int s = value.size();
543				return add(IR::NodeData(Fn::constant, std::move(value)), Sort(s), {});
544			}
545			Node create_pending(int width) {
546				return add(Fn::buf, Sort(width), {});
547			}
548			void update_pending(Node node, Node value) {
549				log_assert(node._ref.function() == Fn::buf && node._ref.size() == 0);
550				log_assert(node.sort() == value.sort());
551				_ir.mutate(node).append_arg(value._ref);
552			}
553			IRInput &add_input(IdString name, IdString kind, Sort sort) {
554				auto [it, inserted] = _ir._inputs.emplace({name, kind}, IRInput(_ir, name, kind, std::move(sort)));
555				if (!inserted) log_error("input `%s` was re-defined", name);
556				return it->second;
557			}
558			IROutput &add_output(IdString name, IdString kind, Sort sort) {
559				auto [it, inserted] = _ir._outputs.emplace({name, kind}, IROutput(_ir, name, kind, std::move(sort)));
560				if (!inserted) log_error("output `%s` was re-defined", name);
561				return it->second;
562			}
563			IRState &add_state(IdString name, IdString kind, Sort sort) {
564				auto [it, inserted] = _ir._states.emplace({name, kind}, IRState(_ir, name, kind, std::move(sort)));
565				if (!inserted) log_error("state `%s` was re-defined", name);
566				return it->second;
567			}
568			Node value(IRInput const& input) {
569				return add(IR::NodeData(Fn::input, std::pair(input.name, input.kind)), input.sort, {});
570			}
571			Node value(IRState const& state) {
572				return add(IR::NodeData(Fn::state, std::pair(state.name, state.kind)), state.sort, {});
573			}
574			void suggest_name(Node node, IdString name) {
575				_ir.mutate(node).sparse_attr() = name;
576			}
577		};
578		inline Factory IR::factory() { return Factory(*this); }
579		template<class Id> class Scope {
580		protected:
581			char substitution_character = '_';
582			virtual bool is_character_legal(char, int) = 0;
583		private:
584			pool<std::string> _used_names;
585			dict<Id, std::string> _by_id;
586		public:
587			void reserve(std::string name) {
588				_used_names.insert(std::move(name));
589			}
590			std::string unique_name(IdString suggestion) {
591				std::string str = suggestion.unescape();
592				for(size_t i = 0; i < str.size(); i++)
593					if(!is_character_legal(str[i], i))
594						str[i] = substitution_character;
595				if(_used_names.count(str) == 0) {
596					_used_names.insert(str);
597					return str;
598				}
599				for (int idx = 0 ; ; idx++){
600					std::string suffixed = str + "_" + std::to_string(idx);
601					if(_used_names.count(suffixed) == 0) {
602						_used_names.insert(suffixed);
603						return suffixed;
604					}
605				}
606			}
607			std::string operator()(Id id, IdString suggestion) {
608				auto it = _by_id.find(id);
609				if(it != _by_id.end())
610					return it->second;
611				std::string str = unique_name(suggestion);
612				_by_id.insert({id, str});
613				return str;
614			}
615		};
616		class Writer {
617			std::ostream *os;
618			void print_impl(const char *fmt, vector<std::function<void()>>& fns);
619		public:
620			Writer(std::ostream &os) : os(&os) {}
621			template<class T> Writer& operator <<(T&& arg) { *os << std::forward<T>(arg); return *this; }
622			template<typename... Args>
623			void print(const char *fmt, Args&&... args)
624			{
625				vector<std::function<void()>> fns { [&]() { *this << args; }... };
626				print_impl(fmt, fns);
627			}
628			template<typename Fn, typename... Args>
629			void print_with(Fn fn, const char *fmt, Args&&... args)
630			{
631				vector<std::function<void()>> fns { [&]() {
632					if constexpr (std::is_invocable_v<Fn, Args>)
633						*this << fn(args);
634					else
635						*this << args; }...
636				};
637				print_impl(fmt, fns);
638			}
639		};
640	
641	}
642	
643	YOSYS_NAMESPACE_END
644	
645	#endif
