24	AigNode::AigNode()
25	{
26		portbit = -1;
27		inverter = false;
28		left_parent = -1;
29		right_parent = -1;
30	}
31	
32	bool AigNode::operator==(const AigNode &other) const
33	{
34		if (portname != other.portname) return false;
35		if (portbit != other.portbit) return false;
36		if (inverter != other.inverter) return false;
37		if (left_parent != other.left_parent) return false;
38		if (right_parent != other.right_parent) return false;
39		return true;
40	}
41	
42	Hasher AigNode::hash_into(Hasher h) const
43	{
44		h.eat(portname);
45		h.eat(portbit);
46		h.eat(inverter);
47		h.eat(left_parent);
48		h.eat(right_parent);
49		return h;
50	}
51	
52	bool Aig::operator==(const Aig &other) const
53	{
54		return name == other.name;
55	}
56	
57	Hasher Aig::hash_into(Hasher h) const
58	{
59		h.eat(name);
60		return h;
61	}
62	
63	struct AigMaker
64	{
65		Aig *aig;
66		Cell *cell;
67		idict<AigNode> aig_indices;
68	
69		AigMaker(Aig *aig, Cell *cell) : aig(aig), cell(cell) {}
70	
71		int node2index(const AigNode &node)
72		{
73			if (node.left_parent > node.right_parent) {
74				AigNode n(node);
75				std::swap(n.left_parent, n.right_parent);
76				return node2index(n);
77			}
78	
79			if (!aig_indices.count(node)) {
80				aig_indices.expect(node, GetSize(aig->nodes));
81				aig->nodes.push_back(node);
82			}
83	
84			return aig_indices.at(node);
85		}
86	
87		int bool_node(bool value)
88		{
89			AigNode node;
90			node.inverter = value;
91			return node2index(node);
92		}
93	
94		int inport(IdString portname, int portbit = 0, bool inverter = false)
95		{
96			if (portbit >= GetSize(cell->getPort(portname))) {
97				if (cell->parameters.count(portname.str() + "_SIGNED") && cell->getParam(portname.str() + "_SIGNED").as_bool())
98					return inport(portname, GetSize(cell->getPort(portname))-1, inverter);
99				return bool_node(inverter);
100			}
101	
102			AigNode node;
103			node.portname = portname;
104			node.portbit = portbit;
105			node.inverter = inverter;
106			return node2index(node);
107		}
108	
109		vector<int> inport_vec(IdString portname, int width)
110		{
111			vector<int> vec;
112			for (int i = 0; i < width; i++)
113				vec.push_back(inport(portname, i));
114			return vec;
115		}
116	
117		int not_inport(IdString portname, int portbit = 0)
118		{
119			return inport(portname, portbit, true);
120		}
121	
122		int not_gate(int A)
123		{
124			AigNode node(aig_indices[A]);
125			node.outports.clear();
126			node.inverter = !node.inverter;
127			return node2index(node);
128		}
129	
130		int and_gate(int A, int B, bool inverter = false)
131		{
132			if (A == B)
133				return inverter ? not_gate(A) : A;
134	
135			const AigNode &nA = aig_indices[A];
136			const AigNode &nB = aig_indices[B];
137	
138			AigNode nB_inv(nB);
139			nB_inv.inverter = !nB_inv.inverter;
140	
141			if (nA == nB_inv)
142				return bool_node(inverter);
143	
144			bool nA_bool = nA.portbit < 0 && nA.left_parent < 0 && nA.right_parent < 0;
145			bool nB_bool = nB.portbit < 0 && nB.left_parent < 0 && nB.right_parent < 0;
146	
147			if (nA_bool && nB_bool) {
148				bool bA = nA.inverter;
149				bool bB = nB.inverter;
150				return bool_node(inverter != (bA && bB));
151			}
152	
153			if (nA_bool) {
154				bool bA = nA.inverter;
155				if (inverter)
156					return bA ? not_gate(B) : bool_node(true);
157				return bA ? B : bool_node(false);
158			}
159	
160			if (nB_bool) {
161				bool bB = nB.inverter;
162				if (inverter)
163					return bB ? not_gate(A) : bool_node(true);
164				return bB ? A : bool_node(false);
165			}
166	
167			AigNode node;
168			node.inverter = inverter;
169			node.left_parent = A;
170			node.right_parent = B;
171			return node2index(node);
172		}
173	
174		int nand_gate(int A, int B)
175		{
176			return and_gate(A, B, true);
177		}
178	
179		int or_gate(int A, int B)
180		{
181			int not_a = not_gate(A);
182			int not_b = not_gate(B);
183			return nand_gate(not_a, not_b);
184		}
185	
186		int nor_gate(int A, int B)
187		{
188			int not_a = not_gate(A);
189			int not_b = not_gate(B);
190			return and_gate(not_a, not_b);
191		}
192	
193		int xor_gate(int A, int B)
194		{
195			int a_and_b = and_gate(A, B);
196			int a_nor_b = nor_gate(A, B);
197			return nor_gate(a_and_b, a_nor_b);
198		}
199	
200		int xnor_gate(int A, int B)
201		{
202			int a_and_b = and_gate(A, B);
203			int a_nor_b = nor_gate(A, B);
204			return or_gate(a_and_b, a_nor_b);
205		}
206	
207		int andnot_gate(int A, int B)
208		{
209			int not_b = not_gate(B);
210			return and_gate(A, not_b);
211		}
212	
213		int ornot_gate(int A, int B)
214		{
215			int not_b = not_gate(B);
216			return or_gate(A, not_b);
217		}
218	
219		int mux_gate(int A, int B, int S)
220		{
221			int not_s = not_gate(S);
222			int a_active = and_gate(A, not_s);
223			int b_active = and_gate(B, S);
224			return or_gate(a_active, b_active);
225		}
226	
227		vector<int> adder(const vector<int> &A, const vector<int> &B, int carry_in, vector<int> *X = nullptr, vector<int> *CO = nullptr)
228		{
229			vector<int> Y(GetSize(A));
230			log_assert(GetSize(A) == GetSize(B));
231			for (int i = 0; i < GetSize(A); i++) {
232				int a_xor_b = xor_gate(A[i], B[i]);
233				int a_or_b = or_gate(A[i], B[i]);
234				int a_and_b = and_gate(A[i], B[i]);
235				Y[i] = xor_gate(a_xor_b, carry_in);
236				int tmp = and_gate(a_or_b, carry_in);
237				int carry_out = or_gate(a_and_b, tmp);
238				if (X != nullptr)
239					X->at(i) = a_xor_b;
240				if (CO != nullptr)
241					CO->at(i) = carry_out;
242				carry_in = carry_out;
243			}
244			return Y;
245		}
246	
247		void outport(int node, IdString portname, int portbit = 0)
248		{
249			if (portbit < GetSize(cell->getPort(portname)))
250				aig->nodes.at(node).outports.push_back(pair<IdString, int>(portname, portbit));
251		}
252	
253		void outport_bool(int node, IdString portname)
254		{
255			outport(node, portname);
256			for (int i = 1; i < GetSize(cell->getPort(portname)); i++)
257				outport(bool_node(false), portname, i);
258		}
259	
260		void outport_vec(const vector<int> &vec, IdString portname)
261		{
262			for (int i = 0; i < GetSize(vec); i++)
263				outport(vec.at(i), portname, i);
264		}
265	};
266	
267	Aig::Aig(Cell *cell)
268	{
269		if (cell->type[0] != '$')
270			return;
271	
272		AigMaker mk(this, cell);
273		name = cell->type.str();
274	
275		string mkname_last;
276		bool mkname_a_signed = false;
277		bool mkname_b_signed = false;
278		bool mkname_is_signed = false;
279	
280		cell->parameters.sort();
281		for (auto p : cell->parameters)
282		{
283			if (p.first == ID::A_WIDTH && mkname_a_signed) {
284				name = mkname_last + stringf(":%d%c", p.second.as_int(), mkname_is_signed ? 'S' : 'U');
285			} else if (p.first == ID::B_WIDTH && mkname_b_signed) {
286				name = mkname_last + stringf(":%d%c", p.second.as_int(), mkname_is_signed ? 'S' : 'U');
287			} else {
288				mkname_last = name;
289				name += stringf(":%d", p.second.as_int());
290			}
291	
292			mkname_a_signed = false;
293			mkname_b_signed = false;
294			mkname_is_signed = false;
295			if (p.first == ID::A_SIGNED) {
296				mkname_a_signed = true;
297				mkname_is_signed = p.second.as_bool();
298			}
299			if (p.first == ID::B_SIGNED) {
300				mkname_b_signed = true;
301				mkname_is_signed = p.second.as_bool();
302			}
303		}
304	
305		if (cell->type.in(ID($not), ID($_NOT_), ID($pos), ID($buf), ID($_BUF_)))
306		{
307			for (int i = 0; i < GetSize(cell->getPort(ID::Y)); i++) {
308				int A = mk.inport(ID::A, i);
309				int Y = cell->type.in(ID($not), ID($_NOT_)) ? mk.not_gate(A) : A;
310				mk.outport(Y, ID::Y, i);
311			}
312			goto optimize;
313		}
314	
315		if (cell->type.in(ID($and), ID($_AND_), ID($_NAND_), ID($or), ID($_OR_), ID($_NOR_), ID($xor), ID($xnor), ID($_XOR_), ID($_XNOR_), ID($_ANDNOT_), ID($_ORNOT_)))
316		{
317			for (int i = 0; i < GetSize(cell->getPort(ID::Y)); i++) {
318				int A = mk.inport(ID::A, i);
319				int B = mk.inport(ID::B, i);
320				int Y = cell->type.in(ID($and), ID($_AND_))   ? mk.and_gate(A, B) :
321				        cell->type.in(ID($_NAND_))            ? mk.nand_gate(A, B) :
322				        cell->type.in(ID($or), ID($_OR_))     ? mk.or_gate(A, B) :
323				        cell->type.in(ID($_NOR_))             ? mk.nor_gate(A, B) :
324				        cell->type.in(ID($xor), ID($_XOR_))   ? mk.xor_gate(A, B) :
325				        cell->type.in(ID($xnor), ID($_XNOR_)) ? mk.xnor_gate(A, B) :
326				        cell->type.in(ID($_ANDNOT_))          ? mk.andnot_gate(A, B) :
327				        cell->type.in(ID($_ORNOT_))           ? mk.ornot_gate(A, B) : -1;
328				mk.outport(Y, ID::Y, i);
329			}
330			goto optimize;
331		}
332	
333		if (cell->type.in(ID($mux), ID($_MUX_), ID($_NMUX_)))
334		{
335			int S = mk.inport(ID::S);
336			for (int i = 0; i < GetSize(cell->getPort(ID::Y)); i++) {
337				int A = mk.inport(ID::A, i);
338				int B = mk.inport(ID::B, i);
339				int Y = mk.mux_gate(A, B, S);
340				if (cell->type == ID($_NMUX_))
341					Y = mk.not_gate(Y);
342				mk.outport(Y, ID::Y, i);
343			}
344			goto optimize;
345		}
346	
347		if (cell->type.in(ID($reduce_and), ID($reduce_or), ID($reduce_xor), ID($reduce_xnor), ID($reduce_bool)))
348		{
349			int Y = mk.inport(ID::A, 0);
350			for (int i = 1; i < GetSize(cell->getPort(ID::A)); i++) {
351				int A = mk.inport(ID::A, i);
352				if (cell->type == ID($reduce_and))  Y = mk.and_gate(A, Y);
353				if (cell->type == ID($reduce_or))   Y = mk.or_gate(A, Y);
354				if (cell->type == ID($reduce_bool)) Y = mk.or_gate(A, Y);
355				if (cell->type == ID($reduce_xor))  Y = mk.xor_gate(A, Y);
356				if (cell->type == ID($reduce_xnor)) Y = mk.xor_gate(A, Y);
357			}
358			if (cell->type == ID($reduce_xnor))
359				Y = mk.not_gate(Y);
360			mk.outport(Y, ID::Y, 0);
361			for (int i = 1; i < GetSize(cell->getPort(ID::Y)); i++)
362				mk.outport(mk.bool_node(false), ID::Y, i);
363			goto optimize;
364		}
365	
366		if (cell->type.in(ID($logic_not), ID($logic_and), ID($logic_or)))
367		{
368			int A = mk.inport(ID::A, 0), Y = -1;
369			for (int i = 1; i < GetSize(cell->getPort(ID::A)); i++)
370				A = mk.or_gate(mk.inport(ID::A, i), A);
371			if (cell->type.in(ID($logic_and), ID($logic_or))) {
372				int B = mk.inport(ID::B, 0);
373				for (int i = 1; i < GetSize(cell->getPort(ID::B)); i++)
374					B = mk.or_gate(mk.inport(ID::B, i), B);
375				if (cell->type == ID($logic_and)) Y = mk.and_gate(A, B);
376				if (cell->type == ID($logic_or))  Y = mk.or_gate(A, B);
377			} else {
378				if (cell->type == ID($logic_not)) Y = mk.not_gate(A);
379			}
380			mk.outport_bool(Y, ID::Y);
381			goto optimize;
382		}
383	
384		if (cell->type.in(ID($add), ID($sub)))
385		{
386			int width = GetSize(cell->getPort(ID::Y));
387			vector<int> A = mk.inport_vec(ID::A, width);
388			vector<int> B = mk.inport_vec(ID::B, width);
389			int carry = mk.bool_node(false);
390			if (cell->type == ID($sub)) {
391				for (auto &n : B)
392					n = mk.not_gate(n);
393				carry = mk.not_gate(carry);
394			}
395			vector<int> Y = mk.adder(A, B, carry);
396			mk.outport_vec(Y, ID::Y);
397			goto optimize;
398		}
399	
400		if (cell->type.in(ID($lt), ID($gt), ID($le), ID($ge)))
401		{
402			int width = std::max(GetSize(cell->getPort(ID::A)),
403								 GetSize(cell->getPort(ID::B))) + 1;
404			vector<int> A = mk.inport_vec(ID::A, width);
405			vector<int> B = mk.inport_vec(ID::B, width);
406	
407			if (cell->type.in(ID($gt), ID($ge)))
408				std::swap(A, B);
409	
410			int carry = mk.bool_node(!cell->type.in(ID($le), ID($ge)));
411			for (auto &n : B)
412				n = mk.not_gate(n);
413			vector<int> Y = mk.adder(A, B, carry);
414			mk.outport(Y.back(), ID::Y);
415			for (int i = 1; i < GetSize(cell->getPort(ID::Y)); i++)
416				mk.outport(mk.bool_node(false), ID::Y, i);
417			goto optimize;
418		}
419	
420		if (cell->type == ID($alu))
421		{
422			int width = GetSize(cell->getPort(ID::Y));
423			vector<int> A = mk.inport_vec(ID::A, width);
424			vector<int> B = mk.inport_vec(ID::B, width);
425			int carry = mk.inport(ID::CI);
426			int binv = mk.inport(ID::BI);
427			for (auto &n : B)
428				n = mk.xor_gate(n, binv);
429			vector<int> X(width), CO(width);
430			vector<int> Y = mk.adder(A, B, carry, &X, &CO);
431			for (int i = 0; i < width; i++)
432				X[i] = mk.xor_gate(A[i], B[i]);
433			mk.outport_vec(Y, ID::Y);
434			mk.outport_vec(X, ID::X);
435			mk.outport_vec(CO, ID::CO);
436			goto optimize;
437		}
438	
439		if (cell->type.in(ID($eq), ID($ne)))
440		{
441			int width = max(GetSize(cell->getPort(ID::A)), GetSize(cell->getPort(ID::B)));
442			vector<int> A = mk.inport_vec(ID::A, width);
443			vector<int> B = mk.inport_vec(ID::B, width);
444			int Y = mk.bool_node(false);
445			for (int i = 0; i < width; i++)
446				Y = mk.or_gate(Y, mk.xor_gate(A[i], B[i]));
447			if (cell->type == ID($eq))
448				Y = mk.not_gate(Y);
449			mk.outport_bool(Y, ID::Y);
450			goto optimize;
451		}
452	
453		if (cell->type == ID($_AOI3_))
454		{
455			int A = mk.inport(ID::A);
456			int B = mk.inport(ID::B);
457			int C = mk.inport(ID::C);
458			int Y = mk.nor_gate(mk.and_gate(A, B), C);
459			mk.outport(Y, ID::Y);
460			goto optimize;
461		}
462	
463		if (cell->type == ID($_OAI3_))
464		{
465			int A = mk.inport(ID::A);
466			int B = mk.inport(ID::B);
467			int C = mk.inport(ID::C);
468			int Y = mk.nand_gate(mk.or_gate(A, B), C);
469			mk.outport(Y, ID::Y);
470			goto optimize;
471		}
472	
473		if (cell->type == ID($_AOI4_))
474		{
475			int A = mk.inport(ID::A);
476			int B = mk.inport(ID::B);
477			int C = mk.inport(ID::C);
478			int D = mk.inport(ID::D);
479			int a_and_b = mk.and_gate(A, B);
480			int Y = mk.nor_gate(a_and_b, mk.and_gate(C, D));
481			mk.outport(Y, ID::Y);
482			goto optimize;
483		}
484	
485		if (cell->type == ID($_OAI4_))
486		{
487			int A = mk.inport(ID::A);
488			int B = mk.inport(ID::B);
489			int C = mk.inport(ID::C);
490			int D = mk.inport(ID::D);
491			int a_or_b = mk.or_gate(A, B);
492			int Y = mk.nand_gate(a_or_b, mk.or_gate(C, D));
493			mk.outport(Y, ID::Y);
494			goto optimize;
495		}
496	
497		name.clear();
498		return;
499	
500	optimize:;
501		pool<int> used_old_ids;
502		vector<AigNode> new_nodes;
503		dict<int, int> old_to_new_ids;
504		old_to_new_ids[-1] = -1;
505	
506		for (int i = GetSize(nodes)-1; i >= 0; i--) {
507			if (!nodes[i].outports.empty())
508				used_old_ids.insert(i);
509			if (!used_old_ids.count(i))
510				continue;
511			if (nodes[i].left_parent >= 0)
512				used_old_ids.insert(nodes[i].left_parent);
513			if (nodes[i].right_parent >= 0)
514				used_old_ids.insert(nodes[i].right_parent);
515		}
516	
517		for (int i = 0; i < GetSize(nodes); i++) {
518			if (!used_old_ids.count(i))
519				continue;
520			nodes[i].left_parent = old_to_new_ids.at(nodes[i].left_parent);
521			nodes[i].right_parent = old_to_new_ids.at(nodes[i].right_parent);
522			old_to_new_ids[i] = GetSize(new_nodes);
523			new_nodes.push_back(nodes[i]);
524		}
525	
526		new_nodes.swap(nodes);
527	}
528	
529	YOSYS_NAMESPACE_END
