229		dict<IdString, Node> handle_alu(Node a_in, Node b_in, int y_width, bool is_signed, Node ci, Node bi) {
230			Node a = factory.extend(a_in, y_width, is_signed);
231			Node b_uninverted = factory.extend(b_in, y_width, is_signed);
232			Node b = factory.mux(b_uninverted, factory.bitwise_not(b_uninverted), bi);
233			Node x = factory.bitwise_xor(a, b);
234			// we can compute the carry into each bit using (a+b+c)^a^b. since we want the carry out,
235			// i.e. the carry into the next bit, we have to add an extra bit to a and b, and
236			// then slice off the bottom bit of the result.
237			Node a_extra = factory.extend(a, y_width + 1, false);
238			Node b_extra = factory.extend(b, y_width + 1, false);
239			Node y_extra = factory.add(factory.add(a_extra, b_extra), factory.extend(ci, a.width() + 1, false));
240			Node y = factory.slice(y_extra, 0, y_width);
241			Node carries = factory.bitwise_xor(y_extra, factory.bitwise_xor(a_extra, b_extra));
242			Node co = factory.slice(carries, 1, y_width);
243			return {{ID(X), x}, {ID(Y), y}, {ID(CO), co}};
244		}
